 bool llvm::isKnownInversion(const Value *X, const Value *Y) {
+  // Check if both values are ICmpInst and compare samesign flags.
+  const ICmpInst *ICmpX = dyn_cast<ICmpInst>(X);
+  const ICmpInst *ICmpY = dyn_cast<ICmpInst>(Y);
+  if (ICmpX && ICmpY && ICmpX->hasSameSign() != ICmpY->hasSameSign())
+    return false;
   // Handle X = icmp pred A, B, Y = icmp pred A, C.
   Value *A, *B, *C;
   ICmpInst::Predicate Pred1, Pred2;
